// Process Message (n8n Function node)

// Input có 2 dạng:
// 1) Telegram bot: { message: { chat:{id}, message_id, text|photo[...] , ... } }
// 2) Extension webhook: { headers, query, body: { question, pageUrl, options, options_raw }, ... }

const input = $json;

// Case 1: Telegram (giữ nguyên logic cũ)
if (input.message) {
  const message = input.message;
  const chatId = $input.first().json.headers['x-forwarded-for'];
  const messageId = message.message_id;

  if (message.text) {
    return [{
      json: {
        question: message.text,
        pageUrl: "",
        options: [],
        options_raw: [],
        chatId,
        messageId,
        messageType: "text",
        needOCR: false
      }
    }];
  } else if (message.photo && message.photo.length > 0) {
    const photo = message.photo[message.photo.length - 1]; // highest res
    const fileData = $input.first().json.binary?.data || "";

    return [{
      json: {
        photoFileId: photo.file_id,
        imageData: fileData,
        question: "",
        pageUrl: "",
        options: [],
        options_raw: [],
        chatId,
        messageId,
        messageType: "image",
        needOCR: true
      }
    }];
  } else {
    return [{
      json: {
        error: "Vui lòng gửi text hoặc hình ảnh",
        chatId,
        messageId,
        messageType: "unsupported"
      }
    }];
  }
}

// Case 2: Webhook từ extension (payload nằm ở $json.body)
const body = input.body || {};
const question = (body.question || "").trim();
const pageUrl = body.pageUrl || "";
const options = Array.isArray(body.options) ? body.options : [];
const optionsRaw = Array.isArray(body.options_raw) ? body.options_raw : [];
const nghiepvu = body.business || "";

// Kiểm tra needOCR: có imageData HOẶC question là "OCR từ ảnh màn hình" HOẶC có option dạng ảnh
const hasImageData = body.imageData && body.imageData.startsWith('data:image/');
const isOCRQuestion = question === "OCR từ ảnh màn hình";
const hasImageOptions = optionsRaw.some(o => o?.img && (o.img.src || o.img.alt));
const needOCR = hasImageData || isOCRQuestion || hasImageOptions;

// Chuẩn hóa để các node sau dùng chung một schema
return [{
  json: {
    question,
    pageUrl,
    options,
    options_raw: optionsRaw,
    messageType: "webhook",
    needOCR,
    nghiepvu,
    imageData: body.imageData || "" // Thêm imageData để các node sau có thể dùng
  }
}];

const geminiResponse = $input.first().json;
const originalData = $('Process Message').first().json;
const nghiepvu = $('EditHinhANh').first().json.nghiepvu;

let extractedText = '';
try {
  if (geminiResponse.candidates && geminiResponse.candidates[0]) {
    extractedText = geminiResponse.candidates[0].content.parts[0].text;
  }
} catch (e) {
  extractedText = 'Không thể đọc text từ hình ảnh';
}

return [{
  json: {
    question: extractedText,
    nghiepvu: nghiepvu,
    chatId: originalData.chatId,
    messageId: originalData.messageId
  }
}];

try {
  // ---- helpers ----
  function getAiText(ai){
    if (!ai || typeof ai !== 'object') return '';
    if (typeof ai.output === 'string') return ai.output;
    if (typeof ai.text === 'string') return ai.text;
    if (typeof ai.response === 'string') return ai.response;
    if (Array.isArray(ai.choices)) {
      const c = ai.choices[0] || {};
      return c.message?.content || c.text || '';
    }
    return '';
  }
  function ensureBreaks(s){
    if (!s) return '';
    s = s.replace(/\r\n/g, '\n').replace(/[ \t]+$/gm, '');
    // options A./A)/A- -> xuống dòng
    s = s.replace(/(?:^|\s)([A-D])\s*[\.\)\-–:]\s+/g, '\n$1) ');
    // headers
    s = s.replace(/\s*\*{0,2}\s*(Đáp án(?:\s+đúng\s+là)?|Answer)\s*[:：]?\s*/gi, '\n\n**Đáp án:** ');
    s = s.replace(/\s*\*{0,2}\s*(Giải thích|Reason|Explanation)\s*[:：]?\s*/gi, '\n\n**Giải thích:** ');
    s = s.replace(/\s*\*{0,2}\s*(Trích dẫn|Nguồn|Citation|Source)\s*[:：]?\s*/gi, '\n\n**Trích dẫn:** ');
    // bullets
    s = s.replace(/(?:^|\n)[ \t]*[-–•]\s+/g, '\n- ');
    // ngoặc nhiều mục -> bullets (bảo thủ)
    s = s.replace(/\(([^()]{12,200})\)/g, (m, inner) => {
      const parts = inner.split(/\s*,\s*/);
      if (parts.length >= 3 && parts.every(p => p.split(' ').length <= 8)) {
        return '\n' + parts.map(p => `- ${p}`).join('\n');
      }
      return m;
    });
    return s.replace(/\n{3,}/g, '\n\n').trim();
  }

  const ai = $json;
  const answer = ensureBreaks(getAiText(ai));

  // Lấy câu hỏi gốc
  let originalQuestion = '(không rõ)';
  try { const e = $('Edit Fields - OCR').first(); if (e?.json?.input) originalQuestion = e.json.input; } catch {}
  if (originalQuestion === '(không rõ)') {
    try { const o = $('Process OCR Result').first(); if (o?.json?.question) originalQuestion = o.json.question; } catch {}
  }

  const response = [
    `📚 **Câu hỏi:** ${originalQuestion}`,
    '',
    `🤖 **Trả lời:**`,
    answer || '(không có nội dung)',
    '',
    `⏰ _${new Date().toLocaleString('vi-VN')}_`
  ].join('\n');

  return [{ json: { response } }];
} catch (error) {
  return [{ json: { response: `❌ Lỗi: ${error.message||error}` } }];
}

