parameters.query:
select
  id,
  row_data,
  1 - (qa_embedding <=> '{{ 
    JSON.stringify(
      $json.embedding ?? $json.data?.[0]?.embedding ?? $json.embeddings?.[0] ?? $json.vector
    ) 
  }}'::vector(768)) as score
from document_rows
where qa_embedding is not null
order by qa_embedding <=> '{{ 
  JSON.stringify(
    $json.embedding ?? $json.data?.[0]?.embedding ?? $json.embeddings?.[0] ?? $json.vector
  ) 
}}'::vector(768)
limit 1;

