// ===== 1) Row từ Select Top-1 (đang ở $json) =====
const row = $json.row_data || {};
const Q  = row.Question || row['Câu hỏi'] || row['question'] || '';
const A  = row.OptionA  || row['A'] || row['Option A'] || '';
const B  = row.OptionB  || row['B'] || row['Option B'] || '';
const C  = row.OptionC  || row['C'] || row['Option C'] || '';
const D  = row.OptionD  || row['D'] || row['Option D'] || '';
const ansLetterDB = (row.Answer || row['Đáp án'] || '').toString().trim().charAt(0).toUpperCase();
const dbOpts = { A, B, C, D };
const ansTextDB = dbOpts[ansLetterDB] || '';
const explanation = row.Explanation || row['Giải thích'] || row['Explanation'] || '';

// ===== 2) Chỉ lấy từ Process Message =====
const pm = ($items('Process OCR Result', 0, 0)?.[0]?.json) || {};
let pageOpts = [];

// a) Nếu Process Message đã có mảng options
if (Array.isArray(pm.options) && pm.options.length) {
  pageOpts = pm.options.slice();
} else if (Array.isArray(pm.options_raw) && pm.options_raw.length) {
  pageOpts = pm.options_raw.map(o => (o?.text ?? o ?? ''));
}

// b) Chuẩn hoá bỏ tiền tố A)/A./A:
pageOpts = pageOpts.filter(Boolean).map(s => s.toString().trim().replace(/^[A-Da-d][)\.:]\s*/, ''));

// c) Fallback: parse từ chuỗi người dùng gửi trong Process Message
function parseOptionsFromText(text){
  if (!text) return [];
  // Hỗ trợ: xuống dòng, dấu ; , hoặc khoảng trắng lớn giữa các option
  const re = /(?:^|[\n;,]\s*)([A-Da-d])[)\.\:\-]?\s*([\s\S]*?)(?=(?:^|[\n;,]\s*)[A-Da-d][)\.\:\-]?\s*|\s*$)/gi;
  let m, arr = [];
  while ((m = re.exec(text)) !== null) {
    const opt = (m[2] || '').toString().trim();
    if (opt) arr.push(opt);
  }
  return arr;
}
if (!pageOpts.length) {
  // pm.question hoặc message gốc user nhập
  const raw = pm.question || pm.text || pm.input || '';
  pageOpts = parseOptionsFromText(raw);
}

// ===== 3) Similarity để map theo nội dung =====
const letters = ['A','B','C','D','E','F','G'];
const norm = s => (s||'')
  .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
  .toLowerCase()
  .replace(/(?<=\d)[\.,](?=\d)/g,'')   // 1.000.000 → 1000000; 1,000 → 1000
  .replace(/[^\p{L}\p{N}\s]/gu,' ')
  .replace(/\s+/g,' ')
  .trim();

function jaccard(a,b){
  const A=new Set(norm(a).split(' ').filter(w=>w.length>1));
  const B=new Set(norm(b).split(' ').filter(w=>w.length>1));
  if(!A.size||!B.size) return 0;
  let inter=0; for(const w of A) if(B.has(w)) inter++;
  return inter/(A.size+B.size-inter);
}
function sim(a,b){
  const u=norm(a), v=norm(b);
  if (!u || !v) return 0;
  if (u.includes(v) || v.includes(u)) return 0.99;
  return jaccard(a,b);
}

// ===== 4) Map đáp án DB → chữ cái đúng theo thứ tự trên đề =====
let mappedIdx=-1, mappedScore=0;
if (ansTextDB && pageOpts.length){
  for (let i=0;i<pageOpts.length;i++){
    const s = sim(ansTextDB, pageOpts[i]);
    if (s > mappedScore){ mappedScore=s; mappedIdx=i; }
  }
}
const THRESH=0.55;
const pageLetter=(mappedIdx>=0 && mappedScore>=THRESH)?letters[mappedIdx]:ansLetterDB;
const pageText  =(mappedIdx>=0 && mappedScore>=THRESH)?pageOpts[mappedIdx]:ansTextDB;

// ===== 5) Output =====
const out=[];
if (Q) out.push(`📚 **Câu hỏi:** ${Q}`);

// In options theo thứ tự trên đề nếu parse được,
// nếu không thì fallback in OptionA..D trong DB
if (pageOpts.length){
  out.push('');
  for (let i=0;i<pageOpts.length;i++) out.push(`${letters[i]}) ${pageOpts[i]}`);
} else {
  const list=[['A',A],['B',B],['C',C],['D',D]].filter(([,t])=>t);
  if (list.length){ out.push(''); for (const [L,T] of list) out.push(`${L}) ${T}`); }
}

out.push('');
out.push(`✅ **Đáp án đúng:** ${pageLetter} — ${pageText}`);
if (pageLetter !== ansLetterDB) {
  out.push(`_(Trong CSDL: ${ansLetterDB} — ${ansTextDB};)_`);
}
if (explanation) {
  out.push('');
  out.push(`📝 **Giải thích:** ${explanation}`);
}
const sc = Math.round(((Number($json.score)||0)*100));
out.push('');
out.push(`📊 _Độ giống câu hỏi: ${sc}%_`);

return [{
  json: {
    response: out.join('\n'),
    mappedLetter: pageLetter,
    mappedScore,
    debug: { pageOpts, ansLetterDB, ansTextDB, parsedFrom: pm.question ? 'Process Message' : 'fallback' }
  }
}];

